using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;
using VetClinic.Data.Models;

namespace VetClinic.Data;

public class ApplicationDbContext(DbContextOptions<ApplicationDbContext> options) : IdentityDbContext<ApplicationUser>(options)
{
    public DbSet<Owner> Owners => Set<Owner>();
    public DbSet<Patient> Patients => Set<Patient>();
    public DbSet<TreatmentNote> TreatmentNotes => Set<TreatmentNote>();
    public DbSet<Appointment> Appointments => Set<Appointment>();
    public DbSet<Invoice> Invoices => Set<Invoice>();
    public DbSet<InvoiceItem> InvoiceItems => Set<InvoiceItem>();
    public DbSet<Payment> Payments => Set<Payment>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        base.OnModelCreating(modelBuilder);

        modelBuilder.Entity<Owner>(e =>
        {
            e.HasIndex(o => o.Email).IsUnique();
            e.HasMany(o => o.Patients).WithOne(p => p.Owner).HasForeignKey(p => p.OwnerId).OnDelete(DeleteBehavior.Cascade);
        });

        modelBuilder.Entity<Patient>(e =>
        {
            e.HasIndex(p => p.Name);
            e.HasIndex(p => p.Microchip).IsUnique().HasFilter("Microchip IS NOT NULL");
            e.HasMany(p => p.TreatmentNotes).WithOne(t => t.Patient).HasForeignKey(t => t.PatientId).OnDelete(DeleteBehavior.Cascade);
            e.HasMany(p => p.Appointments).WithOne(a => a.Patient).HasForeignKey(a => a.PatientId).OnDelete(DeleteBehavior.Cascade);
        });

        modelBuilder.Entity<Invoice>(e =>
        {
            e.HasOne(i => i.Patient).WithMany().HasForeignKey(i => i.PatientId).OnDelete(DeleteBehavior.Cascade);
            e.HasMany(i => i.Items).WithOne(item => item.Invoice).HasForeignKey(item => item.InvoiceId).OnDelete(DeleteBehavior.Cascade);
            e.HasMany(i => i.Payments).WithOne(p => p.Invoice).HasForeignKey(p => p.InvoiceId).OnDelete(DeleteBehavior.Cascade);
        });

        modelBuilder.Entity<InvoiceItem>(e =>
        {
            e.Ignore(i => i.Total);
        });

        modelBuilder.Entity<Appointment>(e =>
        {
            e.HasIndex(a => a.ScheduledAt);
        });
    }
}

