using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class PatientService(ApplicationDbContext db)
{
    public async Task<List<Patient>> GetAllPatientsAsync()
    {
        return await db.Patients.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
    }

    public async Task<List<Patient>> SearchPatientsAsync(string query)
    {
        return await db.Patients.Include(p => p.Owner)
            .Where(p => p.Name.Contains(query) || p.Owner.LastName.Contains(query) || p.Owner.FirstName.Contains(query))
            .OrderBy(p => p.Name)
            .ToListAsync();
    }

    public async Task<Patient?> GetPatientByIdAsync(int id)
    {
        return await db.Patients
            .Include(p => p.Owner)
            .Include(p => p.TreatmentNotes.OrderByDescending(t => t.Date))
            .Include(p => p.Appointments.OrderByDescending(a => a.ScheduledAt))
            .FirstOrDefaultAsync(p => p.Id == id);
    }

    public async Task<Patient> CreatePatientAsync(Patient patient, Owner owner)
    {
        var existingOwner = await db.Owners.FirstOrDefaultAsync(o => o.Email == owner.Email);
        if (existingOwner != null)
        {
            existingOwner.FirstName = owner.FirstName;
            existingOwner.LastName = owner.LastName;
            existingOwner.Phone = owner.Phone;
            existingOwner.Address = owner.Address;
            patient.Owner = existingOwner;
        }
        else
        {
            patient.Owner = owner;
        }

        db.Patients.Add(patient);
        await db.SaveChangesAsync();
        return patient;
    }

    public async Task UpdatePatientAsync(Patient patient)
    {
        db.Patients.Update(patient);
        await db.SaveChangesAsync();
    }

    public async Task<TreatmentNote> AddTreatmentNoteAsync(TreatmentNote note)
    {
        db.TreatmentNotes.Add(note);
        await db.SaveChangesAsync();
        return note;
    }

    public async Task<List<TreatmentNote>> GetMedicalHistoryAsync(int patientId)
    {
        return await db.TreatmentNotes
            .Where(t => t.PatientId == patientId)
            .OrderByDescending(t => t.Date)
            .ToListAsync();
    }

    public async Task<List<Owner>> GetAllOwnersAsync()
    {
        return await db.Owners.OrderBy(o => o.LastName).ToListAsync();
    }
}

using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class AppointmentService(ApplicationDbContext db)
{
    public async Task<List<Appointment>> GetAppointmentsByDateRangeAsync(DateTime start, DateTime end)
    {
        return await db.Appointments
            .Include(a => a.Patient)
            .Where(a => a.ScheduledAt >= start && a.ScheduledAt < end)
            .OrderBy(a => a.ScheduledAt)
            .ToListAsync();
    }

    public async Task<List<Appointment>> GetTodaysAppointmentsAsync()
    {
        var today = DateTime.Today;
        return await GetAppointmentsByDateRangeAsync(today, today.AddDays(1));
    }

    public async Task<Appointment?> GetAppointmentByIdAsync(int id)
    {
        return await db.Appointments
            .Include(a => a.Patient).ThenInclude(p => p.Owner)
            .FirstOrDefaultAsync(a => a.Id == id);
    }

    public async Task<Appointment> CreateAppointmentAsync(Appointment appointment)
    {
        db.Appointments.Add(appointment);
        await db.SaveChangesAsync();
        return appointment;
    }

    public async Task UpdateAppointmentAsync(Appointment appointment)
    {
        db.Appointments.Update(appointment);
        await db.SaveChangesAsync();
    }

    public async Task<List<DateTime>> GetAvailableSlotsAsync(DateTime date)
    {
        var startOfDay = date.Date.AddHours(8); // Clinic opens at 8 AM
        var endOfDay = date.Date.AddHours(17); // Clinic closes at 5 PM

        var existingAppointments = await db.Appointments
            .Where(a => a.ScheduledAt >= startOfDay && a.ScheduledAt < endOfDay
                        && a.Status != AppointmentStatus.Cancelled)
            .Select(a => a.ScheduledAt)
            .ToListAsync();

        var slots = new List<DateTime>();
        var current = startOfDay;
        while (current < endOfDay)
        {
            if (!existingAppointments.Contains(current))
            {
                slots.Add(current);
            }
            current = current.AddMinutes(30);
        }

        return slots;
    }

    public async Task<int> GetTodaysAppointmentCountAsync()
    {
        var today = DateTime.Today;
        return await db.Appointments
            .CountAsync(a => a.ScheduledAt >= today && a.ScheduledAt < today.AddDays(1)
                             && a.Status != AppointmentStatus.Cancelled);
    }

    public async Task<List<Appointment>> GetUpcomingAppointmentsAsync(int count = 5)
    {
        return await db.Appointments
            .Include(a => a.Patient)
            .Where(a => a.ScheduledAt >= DateTime.Now && a.Status == AppointmentStatus.Scheduled)
            .OrderBy(a => a.ScheduledAt)
            .Take(count)
            .ToListAsync();
    }
}

