@page "/"
@attribute [Authorize]

@inject AppointmentService AppointmentService
@inject PatientService PatientService

<PageTitle>Dashboard - VetClinic</PageTitle>

<h1>Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card text-bg-primary mb-3">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-4">@todaysCount</p>
            </div>
        </div>
    </div>
    <div class="col-md-8">
        <div class="card mb-3">
            <div class="card-header">Upcoming Appointments</div>
            <div class="card-body">
                @if (upcomingAppointments?.Any() == true)
                {
                    <table class="table table-sm">
                        <thead>
                            <tr><th>Time</th><th>Patient</th><th>Reason</th></tr>
                        </thead>
                        <tbody>
                            @foreach (var appt in upcomingAppointments)
                            {
                                <tr>
                                    <td>@appt.ScheduledAt.ToString("g")</td>
                                    <td>@appt.Patient?.Name</td>
                                    <td>@appt.Reason</td>
                                </tr>
                            }
                        </tbody>
                    </table>
                }
                else
                {
                    <p class="text-muted">No upcoming appointments.</p>
                }
            </div>
        </div>
    </div>
</div>

<div class="row">
    <div class="col-md-12">
        <div class="card">
            <div class="card-header">Recent Patients</div>
            <div class="card-body">
                @if (recentPatients?.Any() == true)
                {
                    <table class="table table-sm">
                        <thead>
                            <tr><th>Name</th><th>Species</th><th>Owner</th></tr>
                        </thead>
                        <tbody>
                            @foreach (var p in recentPatients)
                            {
                                <tr>
                                    <td><a href="patients/@p.Id">@p.Name</a></td>
                                    <td>@p.Species</td>
                                    <td>@p.Owner?.FirstName @p.Owner?.LastName</td>
                                </tr>
                            }
                        </tbody>
                    </table>
                }
                else
                {
                    <p class="text-muted">No patients registered yet.</p>
                }
            </div>
        </div>
    </div>
</div>

@code {
    private int todaysCount;
    private List<Appointment>? upcomingAppointments;
    private List<Patient>? recentPatients;

    protected override async Task OnInitializedAsync()
    {
        todaysCount = await AppointmentService.GetTodaysAppointmentCountAsync();
        upcomingAppointments = await AppointmentService.GetUpcomingAppointmentsAsync();
        recentPatients = await PatientService.GetAllPatientsAsync();
        recentPatients = recentPatients.Take(10).ToList();
    }
}

