@page "/patients"
@attribute [Authorize]

@inject PatientService PatientService
@inject NavigationManager Navigation

<PageTitle>Patients - VetClinic</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-3">
    <h1>Patients</h1>
    <a href="patients/register" class="btn btn-primary">Register New Patient</a>
</div>

<div class="mb-3">
    <input type="text" class="form-control" placeholder="Search by patient or owner name..."
           @bind="searchQuery" @bind:event="oninput" @bind:after="SearchAsync" />
</div>

@if (patients == null)
{
    <p>Loading...</p>
}
else if (!patients.Any())
{
    <p class="text-muted">No patients found.</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Name</th>
                <th>Species</th>
                <th>Breed</th>
                <th>Owner</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var patient in patients)
            {
                <tr>
                    <td>@patient.Name</td>
                    <td>@patient.Species</td>
                    <td>@patient.Breed</td>
                    <td>@patient.Owner?.FirstName @patient.Owner?.LastName</td>
                    <td><a href="patients/@patient.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Patient>? patients;
    private string searchQuery = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        patients = await PatientService.GetAllPatientsAsync();
    }

    private async Task SearchAsync()
    {
        if (string.IsNullOrWhiteSpace(searchQuery))
            patients = await PatientService.GetAllPatientsAsync();
        else
            patients = await PatientService.SearchPatientsAsync(searchQuery);
    }
}

@page "/patients/{Id:int}"
@attribute [Authorize]

@inject PatientService PatientService
@inject NavigationManager Navigation

<PageTitle>Patient Details - VetClinic</PageTitle>

@if (patient == null)
{
    <p>Loading...</p>
}
else
{
    <div class="d-flex justify-content-between align-items-center mb-3">
        <h1>@patient.Name</h1>
        <a href="patients" class="btn btn-outline-secondary">Back to List</a>
    </div>

    <div class="row">
        <div class="col-md-6">
            <div class="card mb-3">
                <div class="card-header">Patient Information</div>
                <div class="card-body">
                    @if (!isEditing)
                    {
                        <dl class="row mb-0">
                            <dt class="col-sm-4">Species</dt><dd class="col-sm-8">@patient.Species</dd>
                            <dt class="col-sm-4">Breed</dt><dd class="col-sm-8">@patient.Breed</dd>
                            <dt class="col-sm-4">Date of Birth</dt><dd class="col-sm-8">@patient.DateOfBirth.ToShortDateString()</dd>
                            <dt class="col-sm-4">Weight</dt><dd class="col-sm-8">@(patient.Weight.HasValue ? $"{patient.Weight} kg" : "N/A")</dd>
                            <dt class="col-sm-4">Microchip</dt><dd class="col-sm-8">@(patient.Microchip ?? "N/A")</dd>
                        </dl>
                        <button class="btn btn-sm btn-outline-primary mt-2" @onclick="() => isEditing = true">Edit</button>
                    }
                    else
                    {
                        <EditForm Model="patient" OnValidSubmit="SavePatient">
                            <DataAnnotationsValidator />
                            <div class="mb-2">
                                <label class="form-label">Name</label>
                                <InputText class="form-control" @bind-Value="patient.Name" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Species</label>
                                <InputText class="form-control" @bind-Value="patient.Species" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Breed</label>
                                <InputText class="form-control" @bind-Value="patient.Breed" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Weight (kg)</label>
                                <InputNumber class="form-control" @bind-Value="patient.Weight" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Microchip</label>
                                <InputText class="form-control" @bind-Value="patient.Microchip" />
                            </div>
                            <button type="submit" class="btn btn-sm btn-primary">Save</button>
                            <button type="button" class="btn btn-sm btn-secondary" @onclick="CancelEdit">Cancel</button>
                        </EditForm>
                    }
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-header">Owner</div>
                <div class="card-body">
                    <p><strong>@patient.Owner.FirstName @patient.Owner.LastName</strong></p>
                    <p>Phone: @patient.Owner.Phone</p>
                    <p>Email: @patient.Owner.Email</p>
                    <p>Address: @patient.Owner.Address</p>
                </div>
            </div>
        </div>

        <div class="col-md-6">
            <div class="card mb-3">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <span>Medical History</span>
                    <button class="btn btn-sm btn-primary" @onclick="() => showAddNote = !showAddNote">Add Note</button>
                </div>
                <div class="card-body">
                    @if (showAddNote)
                    {
                        <EditForm Model="newNote" OnValidSubmit="AddTreatmentNote" class="mb-3 p-3 border rounded">
                            <DataAnnotationsValidator />
                            <div class="mb-2">
                                <label class="form-label">Date</label>
                                <InputDate class="form-control" @bind-Value="newNote.Date" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Diagnosis</label>
                                <InputText class="form-control" @bind-Value="newNote.Diagnosis" />
                                <ValidationMessage For="() => newNote.Diagnosis" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Treatment</label>
                                <InputText class="form-control" @bind-Value="newNote.Treatment" />
                                <ValidationMessage For="() => newNote.Treatment" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Medication</label>
                                <InputText class="form-control" @bind-Value="newNote.Medication" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Notes</label>
                                <InputTextArea class="form-control" @bind-Value="newNote.Notes" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Staff Name</label>
                                <InputText class="form-control" @bind-Value="newNote.StaffName" />
                                <ValidationMessage For="() => newNote.StaffName" />
                            </div>
                            <button type="submit" class="btn btn-sm btn-success">Save Note</button>
                        </EditForm>
                    }

                    @if (patient.TreatmentNotes?.Any() == true)
                    {
                        @foreach (var note in patient.TreatmentNotes)
                        {
                            <div class="border-bottom pb-2 mb-2">
                                <small class="text-muted">@note.Date.ToShortDateString() — @note.StaffName</small>
                                <p class="mb-1"><strong>Diagnosis:</strong> @note.Diagnosis</p>
                                <p class="mb-1"><strong>Treatment:</strong> @note.Treatment</p>
                                @if (!string.IsNullOrEmpty(note.Medication))
                                {
                                    <p class="mb-1"><strong>Medication:</strong> @note.Medication</p>
                                }
                                @if (!string.IsNullOrEmpty(note.Notes))
                                {
                                    <p class="mb-0"><em>@note.Notes</em></p>
                                }
                            </div>
                        }
                    }
                    else
                    {
                        <p class="text-muted">No medical history recorded.</p>
                    }
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Patient? patient;
    private bool isEditing;
    private bool showAddNote;
    private TreatmentNote newNote = new() { Date = DateTime.Today };

    protected override async Task OnInitializedAsync()
    {
        patient = await PatientService.GetPatientByIdAsync(Id);
    }

    private async Task SavePatient()
    {
        if (patient != null)
        {
            await PatientService.UpdatePatientAsync(patient);
            isEditing = false;
        }
    }

    private void CancelEdit()
    {
        isEditing = false;
    }

    private async Task AddTreatmentNote()
    {
        newNote.PatientId = Id;
        await PatientService.AddTreatmentNoteAsync(newNote);
        patient = await PatientService.GetPatientByIdAsync(Id);
        newNote = new TreatmentNote { Date = DateTime.Today };
        showAddNote = false;
    }
}

@page "/appointments"
@attribute [Authorize]

@inject AppointmentService AppointmentService
@inject NavigationManager Navigation

<PageTitle>Appointments - VetClinic</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-3">
    <h1>Appointments</h1>
    <a href="appointments/create" class="btn btn-primary">New Appointment</a>
</div>

<div class="mb-3">
    <label class="form-label">Select Date</label>
    <input type="date" class="form-control" style="max-width: 250px;"
           value="@selectedDate.ToString("yyyy-MM-dd")"
           @onchange="OnDateChanged" />
</div>

<div class="row">
    <div class="col-md-8">
        <div class="card">
            <div class="card-header">Appointments for @selectedDate.ToLongDateString()</div>
            <div class="card-body">
                @if (appointments?.Any() == true)
                {
                    <table class="table">
                        <thead>
                            <tr><th>Time</th><th>Patient</th><th>Reason</th><th>Status</th><th></th></tr>
                        </thead>
                        <tbody>
                            @foreach (var appt in appointments)
                            {
                                <tr>
                                    <td>@appt.ScheduledAt.ToString("HH:mm")</td>
                                    <td>@appt.Patient?.Name</td>
                                    <td>@appt.Reason</td>
                                    <td>
                                        <span class="badge @GetStatusBadge(appt.Status)">@appt.Status</span>
                                    </td>
                                    <td><a href="appointments/@appt.Id" class="btn btn-sm btn-outline-primary">Edit</a></td>
                                </tr>
                            }
                        </tbody>
                    </table>
                }
                else
                {
                    <p class="text-muted">No appointments for this day.</p>
                }
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-header">Available Slots</div>
            <div class="card-body">
                @if (availableSlots?.Any() == true)
                {
                    <div class="d-flex flex-wrap gap-1">
                        @foreach (var slot in availableSlots)
                        {
                            <span class="badge text-bg-success">@slot.ToString("HH:mm")</span>
                        }
                    </div>
                }
                else
                {
                    <p class="text-muted">No available slots.</p>
                }
            </div>
        </div>
    </div>
</div>

@code {
    private DateTime selectedDate = DateTime.Today;
    private List<Appointment>? appointments;
    private List<DateTime>? availableSlots;

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task OnDateChanged(ChangeEventArgs e)
    {
        if (DateTime.TryParse(e.Value?.ToString(), out var date))
        {
            selectedDate = date;
            await LoadData();
        }
    }

    private async Task LoadData()
    {
        var start = selectedDate.Date;
        var end = start.AddDays(1);
        appointments = await AppointmentService.GetAppointmentsByDateRangeAsync(start, end);
        availableSlots = await AppointmentService.GetAvailableSlotsAsync(selectedDate);
    }

    private string GetStatusBadge(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "text-bg-primary",
        AppointmentStatus.Completed => "text-bg-success",
        AppointmentStatus.Cancelled => "text-bg-danger",
        _ => "text-bg-secondary"
    };
}

