                            <div class="mb-2">
                                <label class="form-label">Date</label>
                                <InputDate class="form-control" @bind-Value="newNote.Date" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Diagnosis</label>
                                <InputText class="form-control" @bind-Value="newNote.Diagnosis" />
                                <ValidationMessage For="() => newNote.Diagnosis" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Treatment</label>
                                <InputText class="form-control" @bind-Value="newNote.Treatment" />
                                <ValidationMessage For="() => newNote.Treatment" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Medication</label>
                                <InputText class="form-control" @bind-Value="newNote.Medication" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Notes</label>
                                <InputTextArea class="form-control" @bind-Value="newNote.Notes" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Staff Name</label>
                                <InputText class="form-control" @bind-Value="newNote.StaffName" />
                                <ValidationMessage For="() => newNote.StaffName" />
                            </div>
                            <button type="submit" class="btn btn-sm btn-success">Save Note</button>
                        </EditForm>
                    }

                    @if (patient.TreatmentNotes?.Any() == true)
                    {
                        @foreach (var note in patient.TreatmentNotes)
                        {
                            <div class="border-bottom pb-2 mb-2">
                                <small class="text-muted">@note.Date.ToShortDateString() — @note.StaffName</small>
                                <p class="mb-1"><strong>Diagnosis:</strong> @note.Diagnosis</p>
                                <p class="mb-1"><strong>Treatment:</strong> @note.Treatment</p>
                                @if (!string.IsNullOrEmpty(note.Medication))
                                {
                                    <p class="mb-1"><strong>Medication:</strong> @note.Medication</p>
                                }
                                @if (!string.IsNullOrEmpty(note.Notes))
                                {
                                    <p class="mb-0"><em>@note.Notes</em></p>
                                }
                            </div>
                        }
                    }
                    else
                    {
                        <p class="text-muted">No medical history recorded.</p>
                    }
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Patient? patient;
    private bool isEditing;
    private bool showAddNote;
    private TreatmentNote newNote = new() { Date = DateTime.Today };

    protected override async Task OnInitializedAsync()
    {
        patient = await PatientService.GetPatientByIdAsync(Id);
    }

    private async Task SavePatient()
    {
        if (patient != null)
        {
            await PatientService.UpdatePatientAsync(patient);
            isEditing = false;
        }
    }

    private void CancelEdit()
    {
        isEditing = false;
    }

    private async Task AddTreatmentNote()
    {
        newNote.PatientId = Id;
        await PatientService.AddTreatmentNoteAsync(newNote);
        patient = await PatientService.GetPatientByIdAsync(Id);
        newNote = new TreatmentNote { Date = DateTime.Today };
        showAddNote = false;
    }
}

@page "/appointments"
@attribute [Authorize]

@inject AppointmentService AppointmentService
@inject NavigationManager Navigation

<PageTitle>Appointments - VetClinic</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-3">
