</div>

<div class="mb-3">
    <label class="form-label">Select Date</label>
    <input type="date" class="form-control" style="max-width: 250px;"
           value="@selectedDate.ToString("yyyy-MM-dd")"
           @onchange="OnDateChanged" />
</div>

<div class="row">
    <div class="col-md-8">
        <div class="card">
            <div class="card-header">Appointments for @selectedDate.ToLongDateString()</div>
            <div class="card-body">
                @if (appointments?.Any() == true)
                {
                    <table class="table">
                        <thead>
                            <tr><th>Time</th><th>Patient</th><th>Reason</th><th>Status</th><th></th></tr>
                        </thead>
                        <tbody>
                            @foreach (var appt in appointments)
                            {
