                                        <span class="badge @GetStatusBadge(appt.Status)">@appt.Status</span>
                                    </td>
                                    <td><a href="appointments/@appt.Id" class="btn btn-sm btn-outline-primary">Edit</a></td>
                                </tr>
                            }
                        </tbody>
                    </table>
                }
                else
                {
