                }
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-header">Available Slots</div>
            <div class="card-body">
                @if (availableSlots?.Any() == true)
                {
                    <div class="d-flex flex-wrap gap-1">
                        @foreach (var slot in availableSlots)
                        {
                            <span class="badge text-bg-success">@slot.ToString("HH:mm")</span>
                        }
                    </div>
                }
                else
                {
                    <p class="text-muted">No available slots.</p>
                }
            </div>
        </div>
    </div>
</div>

@code {
    private DateTime selectedDate = DateTime.Today;
    private List<Appointment>? appointments;
    private List<DateTime>? availableSlots;

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task OnDateChanged(ChangeEventArgs e)
    {
        if (DateTime.TryParse(e.Value?.ToString(), out var date))
        {
            selectedDate = date;
            await LoadData();
        }
    }

    private async Task LoadData()
    {
        var start = selectedDate.Date;
        var end = start.AddDays(1);
        appointments = await AppointmentService.GetAppointmentsByDateRangeAsync(start, end);
        availableSlots = await AppointmentService.GetAvailableSlotsAsync(selectedDate);
    }

    private string GetStatusBadge(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "text-bg-primary",
        AppointmentStatus.Completed => "text-bg-success",
        AppointmentStatus.Cancelled => "text-bg-danger",
        _ => "text-bg-secondary"
    };
}

@page "/appointments/create"
@attribute [Authorize]

@inject AppointmentService AppointmentService
@inject PatientService PatientService
@inject NavigationManager Navigation

<PageTitle>Create Appointment - VetClinic</PageTitle>

<h1>Create Appointment</h1>

<EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="create-appointment">
    <DataAnnotationsValidator />
    <ValidationSummary class="text-danger" />

    <div class="row">
        <div class="col-md-6 mb-3">
            <label class="form-label">Patient</label>
            <InputSelect class="form-select" @bind-Value="model.PatientId">
                <option value="0">-- Select Patient --</option>
                @if (patients != null)
                {
                    @foreach (var p in patients)
                    {
                        <option value="@p.Id">@p.Name (@p.Owner?.LastName)</option>
                    }
                }
            </InputSelect>
            <ValidationMessage For="() => model.PatientId" />
        </div>
        <div class="col-md-6 mb-3">
            <label class="form-label">Date</label>
            <InputDate class="form-control" @bind-Value="model.Date" @bind-Value:after="LoadSlots" />
        </div>
    </div>

    <div class="row">
        <div class="col-md-6 mb-3">
            <label class="form-label">Time Slot</label>
            <InputSelect class="form-select" @bind-Value="model.TimeSlot">
                <option value="">-- Select Time --</option>
                @if (availableSlots != null)
                {
                    @foreach (var slot in availableSlots)
                    {
                        <option value="@slot.ToString("HH:mm")">@slot.ToString("HH:mm")</option>
                    }
                }
            </InputSelect>
            <ValidationMessage For="() => model.TimeSlot" />
        </div>
        <div class="col-md-6 mb-3">
            <label class="form-label">Duration (minutes)</label>
            <InputNumber class="form-control" @bind-Value="model.DurationMinutes" />
        </div>
    </div>

    <div class="mb-3">
        <label class="form-label">Reason</label>
        <InputText class="form-control" @bind-Value="model.Reason" />
        <ValidationMessage For="() => model.Reason" />
    </div>

    <div class="mb-3">
        <label class="form-label">Notes</label>
        <InputTextArea class="form-control" @bind-Value="model.Notes" />
    </div>

    <button type="submit" class="btn btn-primary">Create Appointment</button>
    <a href="appointments" class="btn btn-secondary ms-2">Cancel</a>
</EditForm>

@code {
    private AppointmentModel model = new();
    private List<Patient>? patients;
    private List<DateTime>? availableSlots;

    protected override async Task OnInitializedAsync()
    {
        patients = await PatientService.GetAllPatientsAsync();
        await LoadSlots();
    }

    private async Task LoadSlots()
    {
        availableSlots = await AppointmentService.GetAvailableSlotsAsync(model.Date);
    }

    private async Task HandleSubmit()
    {
        if (model.PatientId == 0 || string.IsNullOrEmpty(model.TimeSlot)) return;

        var time = TimeSpan.Parse(model.TimeSlot);
        var appointment = new Appointment
        {
            PatientId = model.PatientId,
            ScheduledAt = model.Date.Date.Add(time),
            DurationMinutes = model.DurationMinutes,
            Reason = model.Reason,
            Notes = model.Notes ?? string.Empty,
            Status = AppointmentStatus.Scheduled
        };

        await AppointmentService.CreateAppointmentAsync(appointment);
        Navigation.NavigateTo("appointments");
    }

    private class AppointmentModel
    {
        [Range(1, int.MaxValue, ErrorMessage = "Please select a patient.")]
        public int PatientId { get; set; }

        [Required]
        public DateTime Date { get; set; } = DateTime.Today;

        [Required(ErrorMessage = "Please select a time slot.")]
        public string TimeSlot { get; set; } = string.Empty;

        public int DurationMinutes { get; set; } = 30;

        [Required]
        public string Reason { get; set; } = string.Empty;

        public string? Notes { get; set; }
    }
}

