@code {
    private List<Invoice>? invoices;
    private InvoiceStatus? filter;

    protected override async Task OnInitializedAsync()
    {
        await LoadInvoices();
    }

    private async Task FilterBy(InvoiceStatus? status)
    {
        filter = status;
        await LoadInvoices();
    }

    private async Task LoadInvoices()
    {
        invoices = filter.HasValue
            ? await BillingService.GetInvoicesByStatusAsync(filter.Value)
            : await BillingService.GetAllInvoicesAsync();
    }

    private string GetStatusBadge(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "text-bg-warning",
        InvoiceStatus.Paid => "text-bg-success",
