@attribute [Authorize]

@inject BillingService BillingService
@inject PatientService PatientService
@inject NavigationManager Navigation

<PageTitle>Create Invoice - VetClinic</PageTitle>

<h1>Create Invoice</h1>

<EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="create-invoice">
    <DataAnnotationsValidator />
    <ValidationSummary class="text-danger" />

    <div class="row">
        <div class="col-md-6 mb-3">
            <label class="form-label">Patient</label>
            <InputSelect class="form-select" @bind-Value="model.PatientId">
                <option value="0">-- Select Patient --</option>
                @if (patients != null)
                {
                    @foreach (var p in patients)
                    {
                        <option value="@p.Id">@p.Name (@p.Owner?.LastName)</option>
                    }
                }
            </InputSelect>
        </div>
        <div class="col-md-6 mb-3">
            <label class="form-label">Due Date</label>
            <InputDate class="form-control" @bind-Value="model.DueDate" />
        </div>
    </div>

    <h4>Line Items</h4>
    <table class="table">
        <thead>
            <tr><th>Description</th><th>Qty</th><th>Unit Price</th><th>Total</th><th></th></tr>
        </thead>
        <tbody>
            @for (int i = 0; i < model.Items.Count; i++)
            {
                var index = i;
                <tr>
                    <td><InputText class="form-control" @bind-Value="model.Items[index].Description" /></td>
                    <td style="width:100px"><InputNumber class="form-control" @bind-Value="model.Items[index].Quantity" /></td>
                    <td style="width:130px"><InputNumber class="form-control" @bind-Value="model.Items[index].UnitPrice" /></td>
                    <td>$@((model.Items[index].Quantity * model.Items[index].UnitPrice).ToString("F2"))</td>
                    <td><button type="button" class="btn btn-sm btn-danger" @onclick="() => RemoveItem(index)">×</button></td>
                </tr>
            }
        </tbody>
    </table>

    <button type="button" class="btn btn-sm btn-outline-secondary mb-3" @onclick="AddItem">+ Add Item</button>

    <div class="mb-3">
        <strong>Total: $@model.Items.Sum(i => i.Quantity * i.UnitPrice).ToString("F2")</strong>
    </div>

    <button type="submit" class="btn btn-primary">Create Invoice</button>
    <a href="billing" class="btn btn-secondary ms-2">Cancel</a>
</EditForm>

@code {
    private InvoiceModel model = new();
    private List<Patient>? patients;

    protected override async Task OnInitializedAsync()
    {
        patients = await PatientService.GetAllPatientsAsync();
        model.Items.Add(new ItemModel());
    }

    private void AddItem() => model.Items.Add(new ItemModel());

    private void RemoveItem(int index)
    {
        if (model.Items.Count > 1)
            model.Items.RemoveAt(index);
    }

    private async Task HandleSubmit()
    {
        if (model.PatientId == 0) return;

        var invoice = new Invoice
        {
            PatientId = model.PatientId,
            DueDate = model.DueDate,
            Items = model.Items.Select(i => new InvoiceItem
            {
                Description = i.Description,
                Quantity = i.Quantity,
                UnitPrice = i.UnitPrice
            }).ToList()
        };

        await BillingService.CreateInvoiceAsync(invoice);
        Navigation.NavigateTo("billing");
    }

    private class InvoiceModel
    {
        [Range(1, int.MaxValue)] public int PatientId { get; set; }
        public DateTime DueDate { get; set; } = DateTime.Today.AddDays(30);
        public List<ItemModel> Items { get; set; } = new();
    }

    private class ItemModel
    {
        [Required] public string Description { get; set; } = string.Empty;
        [Range(1, 1000)] public int Quantity { get; set; } = 1;
        [Range(0.01, 100000)] public decimal UnitPrice { get; set; }
    }
}

