                    </dl>

                    <table class="table table-sm">
                        <thead>
                            <tr><th>Description</th><th>Qty</th><th>Unit Price</th><th>Total</th></tr>
                        </thead>
                        <tbody>
                            @foreach (var item in invoice.Items)
                            {
                                <tr>
                                    <td>@item.Description</td>
                                    <td>@item.Quantity</td>
                                    <td>$@item.UnitPrice.ToString("F2")</td>
                                    <td>$@((item.Quantity * item.UnitPrice).ToString("F2"))</td>
                                </tr>
                            }
                        </tbody>
                        <tfoot>
                            <tr>
                                <td colspan="3" class="text-end"><strong>Total:</strong></td>
                                <td><strong>$@invoiceTotal.ToString("F2")</strong></td>
                            </tr>
                            <tr>
                                <td colspan="3" class="text-end"><strong>Paid:</strong></td>
                                <td><strong>$@totalPaid.ToString("F2")</strong></td>
                            </tr>
                            <tr>
                                <td colspan="3" class="text-end"><strong>Balance:</strong></td>
                                <td><strong>$@((invoiceTotal - totalPaid).ToString("F2"))</strong></td>
                            </tr>
                        </tfoot>
                    </table>
                </div>
            </div>
        </div>

        <div class="col-md-4">
            <div class="card mb-3">
                <div class="card-header">Add Payment</div>
                <div class="card-body">
                    @if (invoice.Status != InvoiceStatus.Paid)
                    {
                        <EditForm Model="newPayment" OnValidSubmit="AddPayment" FormName="add-payment">
                            <DataAnnotationsValidator />
                            <div class="mb-2">
                                <label class="form-label">Amount</label>
                                <InputNumber class="form-control" @bind-Value="newPayment.Amount" />
                                <ValidationMessage For="() => newPayment.Amount" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Method</label>
                                <InputSelect class="form-select" @bind-Value="newPayment.Method">
                                    @foreach (var method in Enum.GetValues<PaymentMethod>())
                                    {
                                        <option value="@method">@method</option>
                                    }
                                </InputSelect>
                            </div>
                            <button type="submit" class="btn btn-success w-100">Record Payment</button>
                        </EditForm>
                    }
                    else
                    {
                        <p class="text-success"><strong>Fully Paid</strong></p>
                    }
                </div>
            </div>

            <div class="card">
                <div class="card-header">Payment History</div>
                <div class="card-body">
                    @if (invoice.Payments?.Any() == true)
                    {
                        @foreach (var payment in invoice.Payments)
                        {
                            <div class="border-bottom pb-2 mb-2">
                                <strong>$@payment.Amount.ToString("F2")</strong> — @payment.Method
                                <br /><small class="text-muted">@payment.PaidAt.ToString("g")</small>
                            </div>
                        }
                    }
                    else
                    {
                        <p class="text-muted">No payments recorded.</p>
                    }
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Invoice? invoice;
    private Payment newPayment = new();
    private decimal invoiceTotal;
    private decimal totalPaid;

    protected override async Task OnInitializedAsync()
    {
        await LoadInvoice();
    }

    private async Task LoadInvoice()
    {
        invoice = await BillingService.GetInvoiceByIdAsync(Id);
        if (invoice != null)
        {
            invoiceTotal = invoice.Items.Sum(i => i.Quantity * i.UnitPrice);
            totalPaid = invoice.Payments.Sum(p => p.Amount);
            newPayment.Amount = invoiceTotal - totalPaid;
        }
    }

    private async Task AddPayment()
    {
        newPayment.InvoiceId = Id;
        newPayment.PaidAt = DateTime.UtcNow;
        await BillingService.AddPaymentAsync(newPayment);
        newPayment = new Payment();
        await LoadInvoice();
    }

    private string GetStatusBadge(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "text-bg-warning",
        InvoiceStatus.Paid => "text-bg-success",
        InvoiceStatus.Overdue => "text-bg-danger",
        _ => "text-bg-secondary"
    };
}

